#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 5e5+5;
struct FHQ_Trp{int ls,rs,val,key,sz;}t[N];
int Q,cnt,root;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
mt19937 num(814130521);
int New_node(int k){
    t[++cnt].val=k,t[cnt].key=num();
    t[cnt].sz=1;return cnt;
}
void push_up(int u){
    t[u].sz=t[t[u].ls].sz+t[t[u].rs].sz+1;return;
}
void Split(int u,int k,int &x,int &y){
    if(!u){x=0,y=0;return;}
    if(t[u].val<=k)x=u,Split(t[u].rs,k,t[u].rs,y);
    else y=u,Split(t[u].ls,k,x,t[u].ls);
    push_up(u);return;
}
int Merge(int x,int y){
    if(!x||!y)return max(x,y);
    if(t[x].key>t[y].key){
        t[x].rs=Merge(t[x].rs,y);
        push_up(x);return x;
    }else{
        t[y].ls=Merge(x,t[y].ls);
        push_up(y);return y;
    }
}
void Insert(int k){
    int x=0,y=0;
    Split(root,k,x,y);
    int w=New_node(k);
    root=Merge(Merge(x,w),y);
    return;
}
void Delete(int k){
    int x=0,y=0,z=0;
    Split(root,k,x,z);
    Split(x,k-1,x,y);
    y=Merge(t[y].ls,t[y].rs);
    root=Merge(Merge(x,y),z);
    return;
}
int Get_rank(int k){
    int x=0,y=0,rk=0;
    Split(root,k-1,x,y);
    rk=t[x].sz+1;
    Merge(x,y);return rk;
}
int Get_num(int rk){
    int u=root;
    while(u){
        if(t[t[u].ls].sz+1==rk)return t[u].val;
        else if(t[t[u].ls].sz>=rk)u=t[u].ls;
        else rk-=(t[t[u].ls].sz+1),u=t[u].rs;
    }return -1;
}
int Find_pre(int k){
    int x=0,y=0;
    Split(root,k-1,x,y);
    int u=x;while(t[u].rs)u=t[u].rs;
    root=Merge(x,y);return u;
}
int Find_nxt(int k){
    int x=0,y=0;
    Split(root,k,x,y);
    int u=y;while(t[u].ls)u=t[u].ls;
    root=Merge(x,y);return u;
}
int main(){
    Q=read();
    while(Q--){
        int opt=read(),x=read();
        if(opt==1)Insert(x);
        else if(opt==2)Delete(x);
        else if(opt==3)cout<<Get_rank(x)<<"\n";
        else if(opt==4)cout<<Get_num(x)<<"\n";
        else if(opt==5)cout<<t[Find_pre(x)].val<<"\n";
        else cout<<t[Find_nxt(x)].val<<"\n";
    }
    return 0;
}
